PRAGMA foreign_keys = OFF;
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:52', 26, 52, 19, 369, 2984, '۞ وَاَوْحَيْنَآ اِلٰى مُوْسٰىٓ اَنْ اَسْرِ بِعِبَادِيْٓ اِنَّكُمْ مُّتَّبَعُوْنَ', 'Kami wahyukan (perintahkan) kepada Musa, “Pergilah pada malam hari dengan hamba-hamba-Ku (Bani Israil). Sesungguhnya kamu pasti akan diikuti.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026052.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:53', 26, 53, 19, 369, 2985, 'فَاَرْسَلَ فِرْعَوْنُ فِى الْمَدَاۤىِٕنِ حٰشِرِيْنَ ۚ ', 'Lalu, Fir‘aun mengirimkan orang ke kota-kota untuk mengumpulkan (bala tentaranya).', '', 'https://everyayah.com/data/Alafasy_128kbps/026053.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:54', 26, 54, 19, 369, 2986, 'اِنَّ هٰٓؤُلَاۤءِ لَشِرْذِمَةٌ قَلِيْلُوْنَۙ ', '(Fir‘aun berkata,) “Sesungguhnya mereka (Bani Israil) hanyalah sekelompok kecil.', '', 'https://everyayah.com/data/Alafasy_128kbps/026054.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:55', 26, 55, 19, 369, 2987, 'وَاِنَّهُمْ لَنَا لَغَاۤىِٕظُوْنَ ۙ  ', 'Sesungguhnya mereka telah membuat kita marah.', '', 'https://everyayah.com/data/Alafasy_128kbps/026055.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:56', 26, 56, 19, 369, 2988, 'وَاِنَّا لَجَمِيْعٌ حٰذِرُوْنَ ۗ ', 'Sesungguhnya kita semua benar-benar harus selalu waspada.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026056.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:57', 26, 57, 19, 369, 2989, 'فَاَخْرَجْنٰهُمْ مِّنْ جَنّٰتٍ وَّعُيُوْنٍ ۙ ', 'Kami keluarkan mereka (Fir‘aun dan kaumnya) dari (negeri mereka yang mempunyai) taman, mata air,', '', 'https://everyayah.com/data/Alafasy_128kbps/026057.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:58', 26, 58, 19, 369, 2990, 'وَّكُنُوْزٍ وَّمَقَامٍ كَرِيْمٍ ۙ ', 'harta kekayaan, dan tempat tinggal yang bagus.540)', '540) Karena mengejar Nabi Musa a.s. dan Bani Israil, Fir‘aun dan bala tentaranya telah keluar dari negeri mereka dengan meninggalkan kerajaan, kebesaran, kemewahan, dan sebagainya.', 'https://everyayah.com/data/Alafasy_128kbps/026058.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:59', 26, 59, 19, 369, 2991, 'كَذٰلِكَۚ وَاَوْرَثْنٰهَا بَنِيْٓ اِسْرَاۤءِيْلَ ۗ ', 'Demikianlah, dan Kami wariskan semuanya kepada Bani Israil.541)', '541) Setelah Fir‘aun dan bala tentaranya binasa, Nabi Musa a.s. dan Bani Israil kembali ke Mesir untuk mengambil harta kekayaan Fir‘aun dan tentaranya. Mereka lalu melanjutkan perjalanan ke Baitulmaqdis.', 'https://everyayah.com/data/Alafasy_128kbps/026059.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:60', 26, 60, 19, 369, 2992, 'فَاَتْبَعُوْهُمْ مُّشْرِقِيْنَ  ', 'Lalu, (Fir‘aun dan bala tentaranya dapat) menyusul mereka pada waktu matahari terbit.', '', 'https://everyayah.com/data/Alafasy_128kbps/026060.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:61', 26, 61, 19, 370, 2993, 'فَلَمَّا تَرٰۤءَا الْجَمْعٰنِ قَالَ اَصْحٰبُ مُوْسٰٓى اِنَّا لَمُدْرَكُوْنَ ۚ  ', 'Ketika kedua golongan itu saling melihat, para pengikut Musa berkata, “Sesungguhnya kita benar-benar akan tersusul.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026061.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:62', 26, 62, 19, 370, 2994, 'قَالَ كَلَّا ۗاِنَّ مَعِيَ رَبِّيْ سَيَهْدِيْنِ', 'Dia (Musa) berkata, “Tidak! Sesungguhnya Tuhanku bersamaku. Dia akan menunjukiku.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026062.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:63', 26, 63, 19, 370, 2995, 'فَاَوْحَيْنَآ اِلٰى مُوْسٰٓى اَنِ اضْرِبْ بِّعَصَاكَ الْبَحْرَۗ فَانْفَلَقَ فَكَانَ كُلُّ فِرْقٍ كَالطَّوْدِ الْعَظِيْمِ ۚ ', 'Lalu, Kami wahyukan kepada Musa, “Pukullah laut dengan tongkatmu itu.” Maka, terbelahlah (laut itu) dan setiap belahan seperti gunung yang sangat besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/026063.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:64', 26, 64, 19, 370, 2996, 'وَاَزْلَفْنَا ثَمَّ الْاٰخَرِيْنَ ۚ ', 'Di sanalah Kami dekatkan kelompok yang lain.542)', '542) Yang dimaksud dengan kelompok yang lain adalah Fir‘aun dan bala tentaranya. Maksud ayat ini adalah bahwa di bagian yang terbelah itu Allah Swt. mendekatkan antara Fir‘aun dan bala tentaranya dengan Nabi Musa a.s. dan Bani Israil.', 'https://everyayah.com/data/Alafasy_128kbps/026064.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:65', 26, 65, 19, 370, 2997, 'وَاَنْجَيْنَا مُوْسٰى وَمَنْ مَّعَهٗٓ اَجْمَعِيْنَ ۚ ', 'Kami selamatkan Musa dan semua orang yang bersamanya.', '', 'https://everyayah.com/data/Alafasy_128kbps/026065.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:66', 26, 66, 19, 370, 2998, 'ثُمَّ اَغْرَقْنَا الْاٰخَرِيْنَ ۗ ', 'Kemudian, Kami tenggelamkan kelompok yang lain.', '', 'https://everyayah.com/data/Alafasy_128kbps/026066.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:67', 26, 67, 19, 370, 2999, 'اِنَّ فِيْ ذٰلِكَ لَاٰيَةً ۗوَمَا كَانَ اَكْثَرُهُمْ مُّؤْمِنِيْنَ  ', 'Sesungguhnya pada yang demikian itu benar-benar terdapat tanda (kekuasaan Allah), tetapi kebanyakan mereka tidak beriman.', '', 'https://everyayah.com/data/Alafasy_128kbps/026067.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:68', 26, 68, 19, 370, 3000, 'وَاِنَّ رَبَّكَ لَهُوَ الْعَزِيْزُ الرَّحِيْمُ ࣖ', 'Sesungguhnya Tuhanmu, Dialah yang benar-benar Maha Perkasa lagi Maha Penyayang.', '', 'https://everyayah.com/data/Alafasy_128kbps/026068.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:69', 26, 69, 19, 370, 3001, 'وَاتْلُ عَلَيْهِمْ نَبَاَ اِبْرٰهِيْمَ ۘ ', 'Bacakanlah kepada mereka berita Ibrahim.', '', 'https://everyayah.com/data/Alafasy_128kbps/026069.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:70', 26, 70, 19, 370, 3002, 'اِذْ قَالَ لِاَبِيْهِ وَقَوْمِهٖ مَا تَعْبُدُوْنَ ', 'Ketika dia (Ibrahim) berkata kepada bapak dan kaumnya, “Apa yang kamu sembah?”', '', 'https://everyayah.com/data/Alafasy_128kbps/026070.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:71', 26, 71, 19, 370, 3003, 'قَالُوْا نَعْبُدُ اَصْنَامًا فَنَظَلُّ لَهَا عٰكِفِيْنَ  ', 'Mereka menjawab, “Kami menyembah berhala-berhala dan senantiasa tekun menyembahnya.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026071.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:72', 26, 72, 19, 370, 3004, 'قَالَ هَلْ يَسْمَعُوْنَكُمْ اِذْ تَدْعُوْنَ ۙ  ', 'Dia (Ibrahim) berkata, “Apakah mereka mendengarmu ketika kamu berdoa (kepadanya)?', '', 'https://everyayah.com/data/Alafasy_128kbps/026072.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:73', 26, 73, 19, 370, 3005, 'اَوْ يَنْفَعُوْنَكُمْ اَوْ يَضُرُّوْنَ  ', 'Atau, (dapatkah) mereka memberi manfaat atau mudarat kepadamu?”', '', 'https://everyayah.com/data/Alafasy_128kbps/026073.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:74', 26, 74, 19, 370, 3006, 'قَالُوْا بَلْ وَجَدْنَآ اٰبَاۤءَنَا كَذٰلِكَ يَفْعَلُوْنَ  ', 'Mereka menjawab, “Tidak, tetapi kami mendapati nenek moyang kami berbuat begitu.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026074.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:75', 26, 75, 19, 370, 3007, 'قَالَ اَفَرَءَيْتُمْ مَّا كُنْتُمْ تَعْبُدُوْنَ ۙ ', 'Dia (Ibrahim) berkata, “Apakah kamu memperhatikan apa yang selalu kamu sembah?', '', 'https://everyayah.com/data/Alafasy_128kbps/026075.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:76', 26, 76, 19, 370, 3008, 'اَنْتُمْ وَاٰبَاۤؤُكُمُ الْاَقْدَمُوْنَ ۙ  ', 'Kamu dan nenek moyangmu terdahulu?', '', 'https://everyayah.com/data/Alafasy_128kbps/026076.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:77', 26, 77, 19, 370, 3009, 'فَاِنَّهُمْ عَدُوٌّ لِّيْٓ اِلَّا رَبَّ الْعٰلَمِيْنَ ۙ ', 'Sesungguhnya mereka itu adalah musuhku, lain halnya Tuhan pemelihara semesta alam.', '', 'https://everyayah.com/data/Alafasy_128kbps/026077.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:78', 26, 78, 19, 370, 3010, 'الَّذِيْ خَلَقَنِيْ فَهُوَ يَهْدِيْنِ ۙ ', '(Allah) yang telah menciptakanku. Maka, Dia (pula) yang memberi petunjuk kepadaku.', '', 'https://everyayah.com/data/Alafasy_128kbps/026078.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:79', 26, 79, 19, 370, 3011, 'وَالَّذِيْ هُوَ يُطْعِمُنِيْ وَيَسْقِيْنِ ۙ ', 'Dia (pula) yang memberiku makan dan minum.', '', 'https://everyayah.com/data/Alafasy_128kbps/026079.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:80', 26, 80, 19, 370, 3012, 'وَاِذَا مَرِضْتُ فَهُوَ يَشْفِيْنِ ۙ  ', 'Apabila aku sakit, Dialah yang menyembuhkanku.', '', 'https://everyayah.com/data/Alafasy_128kbps/026080.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:81', 26, 81, 19, 370, 3013, 'وَالَّذِيْ يُمِيْتُنِيْ ثُمَّ يُحْيِيْنِ ۙ ', '(Dia) yang akan mematikanku, kemudian menghidupkanku (kembali).', '', 'https://everyayah.com/data/Alafasy_128kbps/026081.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:82', 26, 82, 19, 370, 3014, 'وَالَّذِيْٓ اَطْمَعُ اَنْ يَّغْفِرَ لِيْ خَطِيْۤـَٔتِيْ يَوْمَ الدِّيْنِ ۗ', '(Dia) yang sangat kuinginkan untuk mengampuni kesalahanku pada hari Pembalasan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026082.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:83', 26, 83, 19, 370, 3015, 'رَبِّ هَبْ لِيْ حُكْمًا وَّاَلْحِقْنِيْ بِالصّٰلِحِيْنَ ۙ', '(Ibrahim berdoa,) “Wahai Tuhanku, berikanlah kepadaku hukum (ilmu dan hikmah) dan pertemukanlah aku dengan orang-orang saleh.', '', 'https://everyayah.com/data/Alafasy_128kbps/026083.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:84', 26, 84, 19, 371, 3016, 'وَاجْعَلْ لِّيْ لِسَانَ صِدْقٍ فِى الْاٰخِرِيْنَ ۙ ', 'Jadikanlah aku sebagai buah tutur yang baik di kalangan orang-orang (yang datang) kemudian.', '', 'https://everyayah.com/data/Alafasy_128kbps/026084.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:85', 26, 85, 19, 371, 3017, 'وَاجْعَلْنِيْ مِنْ وَّرَثَةِ جَنَّةِ النَّعِيْمِ ۙ', 'Jadikanlah aku termasuk orang yang mewarisi surga yang penuh kenikmatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/026085.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:86', 26, 86, 19, 371, 3018, 'وَاغْفِرْ لِاَبِيْٓ اِنَّهٗ كَانَ مِنَ الضَّاۤلِّيْنَ ۙ ', 'Ampunilah ayahku! Sesungguhnya dia termasuk orang-orang sesat.', '', 'https://everyayah.com/data/Alafasy_128kbps/026086.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:87', 26, 87, 19, 371, 3019, 'وَلَا تُخْزِنِيْ يَوْمَ يُبْعَثُوْنَۙ', 'Janganlah Engkau hinakan aku pada hari mereka dibangkitkan.', '', 'https://everyayah.com/data/Alafasy_128kbps/026087.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:88', 26, 88, 19, 371, 3020, 'يَوْمَ لَا يَنْفَعُ مَالٌ وَّلَا بَنُوْنَ ۙ  ', '(Yaitu) pada hari ketika tidak berguna (lagi) harta dan anak-anak.', '', 'https://everyayah.com/data/Alafasy_128kbps/026088.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:89', 26, 89, 19, 371, 3021, 'اِلَّا مَنْ اَتَى اللّٰهَ بِقَلْبٍ سَلِيْمٍ ۗ ', 'Kecuali, orang yang menghadap Allah dengan hati yang bersih.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026089.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:90', 26, 90, 19, 371, 3022, 'وَاُزْلِفَتِ الْجَنَّةُ لِلْمُتَّقِيْنَ ۙ ', 'Surga didekatkan kepada orang-orang yang bertakwa.', '', 'https://everyayah.com/data/Alafasy_128kbps/026090.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:91', 26, 91, 19, 371, 3023, 'وَبُرِّزَتِ الْجَحِيْمُ لِلْغَاوِيْنَ ۙ ', '(Neraka) Jahim diperlihatkan dengan jelas kepada orang-orang yang sesat.', '', 'https://everyayah.com/data/Alafasy_128kbps/026091.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:92', 26, 92, 19, 371, 3024, 'وَقِيْلَ لَهُمْ اَيْنَ مَا كُنْتُمْ تَعْبُدُوْنَ ۙ ', 'Dikatakan kepada mereka, “Di mana berhala-berhala yang selalu kamu sembah', '', 'https://everyayah.com/data/Alafasy_128kbps/026092.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:93', 26, 93, 19, 371, 3025, 'مِنْ دُوْنِ اللّٰهِ ۗهَلْ يَنْصُرُوْنَكُمْ اَوْ يَنْتَصِرُوْنَ ۗ  ', 'selain Allah? Dapatkah mereka menolongmu atau menolong dirinya sendiri?”', '', 'https://everyayah.com/data/Alafasy_128kbps/026093.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:94', 26, 94, 19, 371, 3026, 'فَكُبْكِبُوْا فِيْهَا هُمْ وَالْغَاوٗنَ ۙ ', 'Mereka (sesembahan itu) dijungkirbalikkan di dalamnya (neraka) bersama orang-orang yang sesat.', '', 'https://everyayah.com/data/Alafasy_128kbps/026094.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:95', 26, 95, 19, 371, 3027, 'وَجُنُوْدُ اِبْلِيْسَ اَجْمَعُوْنَ ۗ  ', '(Begitu pula) bala tentara Iblis (dan) semuanya (dijungkirbalikkan).', '', 'https://everyayah.com/data/Alafasy_128kbps/026095.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:96', 26, 96, 19, 371, 3028, 'قَالُوْا وَهُمْ فِيْهَا يَخْتَصِمُوْنَ  ', 'Mereka (orang-orang sesat) berkata sambil bertengkar di dalamnya (neraka),', '', 'https://everyayah.com/data/Alafasy_128kbps/026096.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:97', 26, 97, 19, 371, 3029, 'تَاللّٰهِ اِنْ كُنَّا لَفِيْ ضَلٰلٍ مُّبِيْنٍ ۙ ', '“Demi Allah, sesungguhnya kami dahulu (di dunia) benar-benar dalam kesesatan yang nyata.', '', 'https://everyayah.com/data/Alafasy_128kbps/026097.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:98', 26, 98, 19, 371, 3030, 'اِذْ نُسَوِّيْكُمْ بِرَبِّ الْعٰلَمِيْنَ ', '(Yaitu) ketika kami mempersamakan kamu (berhala-berhala) dengan Tuhan semesta alam.', '', 'https://everyayah.com/data/Alafasy_128kbps/026098.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:99', 26, 99, 19, 371, 3031, 'وَمَآ اَضَلَّنَآ اِلَّا الْمُجْرِمُوْنَ ', 'Tidak ada yang menyesatkan kami, kecuali para pendosa.', '', 'https://everyayah.com/data/Alafasy_128kbps/026099.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:100', 26, 100, 19, 371, 3032, 'فَمَا لَنَا مِنْ شٰفِعِيْنَ ۙ ', 'Tidak ada pemberi syafaat (penolong) untuk kami.', '', 'https://everyayah.com/data/Alafasy_128kbps/026100.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:101', 26, 101, 19, 371, 3033, 'وَلَا صَدِيْقٍ حَمِيْمٍ  ', 'Tidak pula ada teman akrab.', '', 'https://everyayah.com/data/Alafasy_128kbps/026101.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:102', 26, 102, 19, 371, 3034, 'فَلَوْ اَنَّ لَنَا كَرَّةً فَنَكُوْنَ مِنَ الْمُؤْمِنِيْنَ  ', 'Seandainya dapat kembali (ke dunia), niscaya kami menjadi orang-orang yang beriman.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026102.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:103', 26, 103, 19, 371, 3035, 'اِنَّ فِيْ ذٰلِكَ لَاٰيَةً ۗوَمَا كَانَ اَكْثَرُهُمْ مُّؤْمِنِيْنَ  ', 'Sesungguhnya pada yang demikian itu benar-benar terdapat tanda (kekuasaan Allah), tetapi kebanyakan mereka tidak beriman.', '', 'https://everyayah.com/data/Alafasy_128kbps/026103.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:104', 26, 104, 19, 371, 3036, 'وَاِنَّ رَبَّكَ لَهُوَ الْعَزِيْزُ الرَّحِيْمُ ࣖ ', 'Sesungguhnya Tuhanmu, Dialah yang benar-benar Maha Perkasa lagi Maha Penyayang.', '', 'https://everyayah.com/data/Alafasy_128kbps/026104.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:105', 26, 105, 19, 371, 3037, 'كَذَّبَتْ قَوْمُ نُوْحِ ِۨالْمُرْسَلِيْنَ ۚ ', 'Kaum Nuh telah mendustakan para rasul.', '', 'https://everyayah.com/data/Alafasy_128kbps/026105.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:106', 26, 106, 19, 371, 3038, 'اِذْ قَالَ لَهُمْ اَخُوْهُمْ نُوْحٌ اَلَا تَتَّقُوْنَ ۚ ', 'Ketika saudara mereka, Nuh, berkata kepada mereka, “Mengapa kamu tidak bertakwa?', '', 'https://everyayah.com/data/Alafasy_128kbps/026106.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:107', 26, 107, 19, 371, 3039, 'اِنِّيْ لَكُمْ رَسُوْلٌ اَمِيْنٌ ۙ  ', 'Sesungguhnya aku adalah seorang rasul tepercaya (yang diutus) kepadamu.', '', 'https://everyayah.com/data/Alafasy_128kbps/026107.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:108', 26, 108, 19, 371, 3040, 'فَاتَّقُوا اللّٰهَ وَاَطِيْعُوْنِۚ  ', 'Maka, bertakwalah kepada Allah dan taatlah kepadaku.', '', 'https://everyayah.com/data/Alafasy_128kbps/026108.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:109', 26, 109, 19, 371, 3041, 'وَمَآ اَسْـَٔلُكُمْ عَلَيْهِ مِنْ اَجْرٍۚ اِنْ اَجْرِيَ اِلَّا عَلٰى رَبِّ الْعٰلَمِيْنَ ۚ ', 'Aku tidak meminta imbalan kepadamu atas (ajakan) itu. Imbalanku tidak lain, kecuali dari Tuhan semesta alam.', '', 'https://everyayah.com/data/Alafasy_128kbps/026109.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:110', 26, 110, 19, 371, 3042, 'فَاتَّقُوا اللّٰهَ وَاَطِيْعُوْنِ  ', 'Maka, bertakwalah kepada Allah dan taatlah kepadaku.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026110.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:111', 26, 111, 19, 371, 3043, '۞ قَالُوْٓا اَنُؤْمِنُ لَكَ وَاتَّبَعَكَ الْاَرْذَلُوْنَ ۗ ', 'Mereka berkata, “Apakah kami harus beriman kepadamu, padahal yang mengikutimu adalah orang-orang hina?”', '', 'https://everyayah.com/data/Alafasy_128kbps/026111.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:112', 26, 112, 19, 372, 3044, 'قَالَ وَمَا عِلْمِيْ بِمَا كَانُوْا يَعْمَلُوْنَ ۚ  ', 'Dia (Nuh) menjawab, “Apa pengetahuanku tentang apa yang biasa mereka kerjakan?', '', 'https://everyayah.com/data/Alafasy_128kbps/026112.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:113', 26, 113, 19, 372, 3045, 'اِنْ حِسَابُهُمْ اِلَّا عَلٰى رَبِّيْ لَوْ تَشْعُرُوْنَ ۚ  ', 'Perhitungan (amal) mereka tidak lain, kecuali ada pada Tuhanku jika kamu menyadari.', '', 'https://everyayah.com/data/Alafasy_128kbps/026113.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:114', 26, 114, 19, 372, 3046, 'وَمَآ اَنَا۠ بِطَارِدِ الْمُؤْمِنِيْنَ ۚ ', 'Aku tidak akan mengusir orang-orang yang beriman.', '', 'https://everyayah.com/data/Alafasy_128kbps/026114.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:115', 26, 115, 19, 372, 3047, 'اِنْ اَنَا۠ اِلَّا نَذِيْرٌ مُّبِيْنٌ ۗ ', 'Aku tidak lain, kecuali pemberi peringatan yang jelas.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026115.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:116', 26, 116, 19, 372, 3048, 'قَالُوْا لَىِٕنْ لَّمْ تَنْتَهِ يٰنُوْحُ لَتَكُوْنَنَّ مِنَ الْمَرْجُوْمِيْنَۗ  ', 'Mereka berkata, “Wahai Nuh, jika tidak berhenti (dalam berdakwah), niscaya engkau akan termasuk orang-orang yang dirajam.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026116.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:117', 26, 117, 19, 372, 3049, 'قَالَ رَبِّ اِنَّ قَوْمِيْ كَذَّبُوْنِۖ ', 'Dia (Nuh) berkata, “Wahai Tuhanku, sesungguhnya kaumku telah mendustakanku.', '', 'https://everyayah.com/data/Alafasy_128kbps/026117.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:118', 26, 118, 19, 372, 3050, 'فَافْتَحْ بَيْنِيْ وَبَيْنَهُمْ فَتْحًا وَّنَجِّنِيْ وَمَنْ مَّعِيَ مِنَ الْمُؤْمِنِيْنَ  ', 'Maka, berilah keputusan antara aku dan mereka serta selamatkanlah aku dan orang-orang mukmin bersamaku.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026118.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:119', 26, 119, 19, 372, 3051, 'فَاَنْجَيْنٰهُ وَمَنْ مَّعَهٗ فِى الْفُلْكِ الْمَشْحُوْنِ  ', 'Kami selamatkan dia (Nuh) dan orang-orang yang bersamanya di dalam kapal yang penuh muatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/026119.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:120', 26, 120, 19, 372, 3052, 'ثُمَّ اَغْرَقْنَا بَعْدُ الْبَاقِيْنَ  ', 'Kemudian, Kami tenggelamkan orang-orang yang tersisa (tidak beriman) setelah itu.', '', 'https://everyayah.com/data/Alafasy_128kbps/026120.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:121', 26, 121, 19, 372, 3053, 'اِنَّ فِيْ ذٰلِكَ لَاٰيَةً ۗوَمَا كَانَ اَكْثَرُهُمْ مُّؤْمِنِيْنَ  ', 'Sesungguhnya pada yang demikian itu benar-benar terdapat tanda (kekuasaan Allah), tetapi kebanyakan mereka tidak beriman.', '', 'https://everyayah.com/data/Alafasy_128kbps/026121.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:122', 26, 122, 19, 372, 3054, 'وَاِنَّ رَبَّكَ لَهُوَ الْعَزِيْزُ الرَّحِيْمُ ࣖ ', 'Sesungguhnya Tuhanmu, Dialah yang benar-benar Maha Perkasa lagi Maha Penyayang.', '', 'https://everyayah.com/data/Alafasy_128kbps/026122.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:123', 26, 123, 19, 372, 3055, 'كَذَّبَتْ عَادُ ِۨالْمُرْسَلِيْنَ ۖ ', '(Kaum) ‘Ad telah mendustakan para rasul.', '', 'https://everyayah.com/data/Alafasy_128kbps/026123.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:124', 26, 124, 19, 372, 3056, 'اِذْ قَالَ لَهُمْ اَخُوْهُمْ هُوْدٌ اَلَا تَتَّقُوْنَ ۚ ', 'Ketika saudara mereka, Hud, berkata kepada mereka, “Mengapa kamu tidak bertakwa?', '', 'https://everyayah.com/data/Alafasy_128kbps/026124.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:125', 26, 125, 19, 372, 3057, 'اِنِّيْ لَكُمْ رَسُوْلٌ اَمِيْنٌ ۙ ', 'Sesungguhnya aku adalah seorang rasul tepercaya (yang diutus) kepadamu.', '', 'https://everyayah.com/data/Alafasy_128kbps/026125.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:126', 26, 126, 19, 372, 3058, 'فَاتَّقُوا اللّٰهَ وَاَطِيْعُوْنِ ۚ ', 'Maka, bertakwalah kepada Allah dan taatlah kepadaku.', '', 'https://everyayah.com/data/Alafasy_128kbps/026126.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:127', 26, 127, 19, 372, 3059, 'وَمَآ اَسْـَٔلُكُمْ عَلَيْهِ مِنْ اَجْرٍۚ اِنْ اَجْرِيَ اِلَّا عَلٰى رَبِّ الْعٰلَمِيْنَ ۗ ', 'Aku tidak meminta imbalan kepadamu atas (ajakan) itu. Imbalanku tidak lain, kecuali dari Tuhan semesta alam.', '', 'https://everyayah.com/data/Alafasy_128kbps/026127.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:128', 26, 128, 19, 372, 3060, 'اَتَبْنُوْنَ بِكُلِّ رِيْعٍ اٰيَةً تَعْبَثُوْنَ ۙ ', 'Apakah kamu mendirikan istana di setiap tanah yang tinggi untuk kemegahan tanpa ditempati? ', '', 'https://everyayah.com/data/Alafasy_128kbps/026128.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:129', 26, 129, 19, 372, 3061, 'وَتَتَّخِذُوْنَ مَصَانِعَ لَعَلَّكُمْ تَخْلُدُوْنَۚ  ', 'Kamu (juga) membuat benteng-benteng dengan harapan hidup kekal?', '', 'https://everyayah.com/data/Alafasy_128kbps/026129.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:130', 26, 130, 19, 372, 3062, 'وَاِذَا بَطَشْتُمْ بَطَشْتُمْ جَبَّارِيْنَۚ  ', 'Apabila menyiksa, kamu lakukan secara kejam dan bengis.', '', 'https://everyayah.com/data/Alafasy_128kbps/026130.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:131', 26, 131, 19, 372, 3063, 'فَاتَّقُوا اللّٰهَ وَاَطِيْعُوْنِۚ  ', 'Maka, bertakwalah kepada Allah dan taatlah kepadaku.', '', 'https://everyayah.com/data/Alafasy_128kbps/026131.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:132', 26, 132, 19, 372, 3064, 'وَاتَّقُوا الَّذِيْٓ اَمَدَّكُمْ بِمَا تَعْلَمُوْنَ  ۚ', 'Bertakwalah kepada (Allah) yang telah menganugerahkan kepadamu apa yang kamu ketahui.', '', 'https://everyayah.com/data/Alafasy_128kbps/026132.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:133', 26, 133, 19, 372, 3065, 'اَمَدَّكُمْ بِاَنْعَامٍ وَّبَنِيْنَۙ  ', 'Dia (Allah) telah menganugerahkan hewan ternak dan anak-anak kepadamu.', '', 'https://everyayah.com/data/Alafasy_128kbps/026133.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:134', 26, 134, 19, 372, 3066, 'وَجَنّٰتٍ وَّعُيُوْنٍۚ  ', '(Dia juga menganugerahkan) kebun-kebun dan mata air.', '', 'https://everyayah.com/data/Alafasy_128kbps/026134.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:135', 26, 135, 19, 372, 3067, 'اِنِّيْٓ اَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٍ عَظِيْمٍ ۗ ', 'Sesungguhnya aku takut bahwa kamu akan ditimpa azab pada hari yang dahsyat.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026135.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:136', 26, 136, 19, 372, 3068, 'قَالُوْا سَوَاۤءٌ عَلَيْنَآ اَوَعَظْتَ اَمْ لَمْ تَكُنْ مِّنَ الْوٰعِظِيْنَ ۙ ', 'Mereka menjawab, “Sama saja bagi kami, apakah engkau memberi nasihat atau tidak memberi nasihat.', '', 'https://everyayah.com/data/Alafasy_128kbps/026136.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:137', 26, 137, 19, 373, 3069, 'اِنْ هٰذَآ اِلَّا خُلُقُ الْاَوَّلِيْنَ ۙ ', '(Agama kami) ini tidak lain adalah agama orang-orang terdahulu.', '', 'https://everyayah.com/data/Alafasy_128kbps/026137.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:138', 26, 138, 19, 373, 3070, 'وَمَا نَحْنُ بِمُعَذَّبِيْنَ ۚ ', 'Kami (sama sekali) tidak akan diazab.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026138.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:139', 26, 139, 19, 373, 3071, 'فَكَذَّبُوْهُ فَاَهْلَكْنٰهُمْۗ اِنَّ فِيْ ذٰلِكَ لَاٰيَةً ۗوَمَا كَانَ اَكْثَرُهُمْ مُّؤْمِنِيْنَ  ', 'Maka, mereka mendustakannya (Hud). Lalu, Kami membinasakan mereka. Sesungguhnya pada yang demikian itu benar-benar terdapat tanda (kekuasaan Allah), tetapi kebanyakan mereka tidak beriman.', '', 'https://everyayah.com/data/Alafasy_128kbps/026139.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:140', 26, 140, 19, 373, 3072, 'وَاِنَّ رَبَّكَ لَهُوَ الْعَزِيْزُ الرَّحِيْمُ ࣖ', 'Sesungguhnya Tuhanmu, Dialah yang benar-benar Maha Perkasa lagi Maha Penyayang.', '', 'https://everyayah.com/data/Alafasy_128kbps/026140.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:141', 26, 141, 19, 373, 3073, 'كَذَّبَتْ ثَمُوْدُ الْمُرْسَلِيْنَ  ۖ ', '(Kaum) Samud telah mendustakan para rasul.', '', 'https://everyayah.com/data/Alafasy_128kbps/026141.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:142', 26, 142, 19, 373, 3074, 'اِذْ قَالَ لَهُمْ اَخُوْهُمْ صٰلِحٌ اَلَا تَتَّقُوْنَ ۚ ', 'Ketika saudara mereka, Saleh, berkata kepada mereka, “Mengapa kamu tidak bertakwa?', '', 'https://everyayah.com/data/Alafasy_128kbps/026142.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:143', 26, 143, 19, 373, 3075, 'اِنِّيْ لَكُمْ رَسُوْلٌ اَمِيْنٌ ۙ  ', 'Sesungguhnya aku adalah seorang rasul tepercaya (yang diutus) kepadamu.', '', 'https://everyayah.com/data/Alafasy_128kbps/026143.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:144', 26, 144, 19, 373, 3076, 'فَاتَّقُوا اللّٰهَ وَاَطِيْعُوْنِ ۚ  ', 'Maka, bertakwalah kepada Allah dan taatlah kepadaku.', '', 'https://everyayah.com/data/Alafasy_128kbps/026144.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:145', 26, 145, 19, 373, 3077, 'وَمَآ اَسْـَٔلُكُمْ عَلَيْهِ مِنْ اَجْرٍۚ اِنْ اَجْرِيَ اِلَّا عَلٰى رَبِّ الْعٰلَمِيْنَ ۗ ', 'Aku tidak meminta imbalan kepadamu atas (ajakan) itu. Imbalanku tidak lain, kecuali dari Tuhan semesta alam.', '', 'https://everyayah.com/data/Alafasy_128kbps/026145.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:146', 26, 146, 19, 373, 3078, 'اَتُتْرَكُوْنَ فِيْ مَا هٰهُنَآ اٰمِنِيْنَ ۙ ', 'Apakah kamu (mengira) akan dibiarkan tinggal di sini (negerimu) dengan aman?', '', 'https://everyayah.com/data/Alafasy_128kbps/026146.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:147', 26, 147, 19, 373, 3079, 'فِيْ جَنّٰتٍ وَّعُيُوْنٍ ۙ ', '(Yaitu,) di dalam kebun-kebun dan mata air.', '', 'https://everyayah.com/data/Alafasy_128kbps/026147.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:148', 26, 148, 19, 373, 3080, 'وَّزُرُوْعٍ وَّنَخْلٍ طَلْعُهَا هَضِيْمٌ ۚ ', 'Dan, tanam-tanaman serta pohon kurma yang mayangnya lembut.', '', 'https://everyayah.com/data/Alafasy_128kbps/026148.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:149', 26, 149, 19, 373, 3081, 'وَتَنْحِتُوْنَ مِنَ الْجِبَالِ بُيُوْتًا فٰرِهِيْنَ ', 'Kamu pahat dengan terampil sebagian gunung-gunung untuk dijadikan rumah-rumah yang mewah.', '', 'https://everyayah.com/data/Alafasy_128kbps/026149.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:150', 26, 150, 19, 373, 3082, 'فَاتَّقُوا اللّٰهَ وَاَطِيْعُوْنِ ۚ ', 'Maka, bertakwalah kepada Allah dan taatlah kepadaku.', '', 'https://everyayah.com/data/Alafasy_128kbps/026150.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:151', 26, 151, 19, 373, 3083, 'وَلَا تُطِيْعُوْٓا اَمْرَ الْمُسْرِفِيْنَ ۙ ', 'Janganlah mengikuti perintah orang-orang yang melampaui batas.', '', 'https://everyayah.com/data/Alafasy_128kbps/026151.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:152', 26, 152, 19, 373, 3084, 'الَّذِيْنَ يُفْسِدُوْنَ فِى الْاَرْضِ وَلَا يُصْلِحُوْنَ  ', '(Mereka) yang berbuat kerusakan di bumi dan tidak melakukan perbaikan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026152.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:153', 26, 153, 19, 373, 3085, 'قَالُوْٓا اِنَّمَآ اَنْتَ مِنَ الْمُسَحَّرِيْنَ ۙ ', 'Mereka berkata, “Sesungguhnya engkau hanyalah termasuk orang-orang yang terkena sihir.', '', 'https://everyayah.com/data/Alafasy_128kbps/026153.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:154', 26, 154, 19, 373, 3086, 'مَآ اَنْتَ اِلَّا بَشَرٌ مِّثْلُنَاۙ فَأْتِ بِاٰيَةٍ اِنْ كُنْتَ مِنَ الصّٰدِقِيْنَ  ', 'Engkau tidak lain hanyalah manusia seperti kami. Maka, datangkanlah tanda (mukjizat) jika engkau termasuk orang-orang yang benar.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026154.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:155', 26, 155, 19, 373, 3087, 'قَالَ هٰذِهٖ نَاقَةٌ لَّهَا شِرْبٌ وَّلَكُمْ شِرْبُ يَوْمٍ مَّعْلُوْمٍ ۚ ', 'Dia (Saleh) menjawab, “Ini seekor unta betina. Dia punya (giliran) minum dan kamu punya (giliran) minum (pula) pada hari yang ditentukan.', '', 'https://everyayah.com/data/Alafasy_128kbps/026155.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:156', 26, 156, 19, 373, 3088, 'وَلَا تَمَسُّوْهَا بِسُوْۤءٍ فَيَأْخُذَكُمْ عَذَابُ يَوْمٍ عَظِيْمٍ  ', 'Janganlah menyentuhnya dengan suatu kejahatan. Nanti kamu akan ditimpa azab pada hari yang dahsyat.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026156.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:157', 26, 157, 19, 373, 3089, 'فَعَقَرُوْهَا فَاَصْبَحُوْا نٰدِمِيْنَ ۙ ', 'Mereka membunuhnya, lalu mereka menjadi orang-orang yang menyesal.', '', 'https://everyayah.com/data/Alafasy_128kbps/026157.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:158', 26, 158, 19, 373, 3090, 'فَاَخَذَهُمُ الْعَذَابُۗ اِنَّ فِيْ ذٰلِكَ لَاٰيَةً ۗوَمَا كَانَ اَكْثَرُهُمْ مُّؤْمِنِيْنَ  ', 'Mereka ditimpa azab. Sesungguhnya pada yang demikian itu benar-benar terdapat tanda (kekuasaan Allah), tetapi kebanyakan mereka tidak beriman.', '', 'https://everyayah.com/data/Alafasy_128kbps/026158.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:159', 26, 159, 19, 373, 3091, 'وَاِنَّ رَبَّكَ لَهُوَ الْعَزِيْزُ الرَّحِيْمُ ࣖ ', 'Sesungguhnya Tuhanmu, Dialah yang benar-benar Maha Perkasa lagi Maha Penyayang.', '', 'https://everyayah.com/data/Alafasy_128kbps/026159.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:160', 26, 160, 19, 374, 3092, 'كَذَّبَتْ قَوْمُ لُوْطِ ِۨالْمُرْسَلِيْنَ ۖ ', 'Kaum Lut telah mendustakan para rasul.', '', 'https://everyayah.com/data/Alafasy_128kbps/026160.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:161', 26, 161, 19, 374, 3093, 'اِذْ قَالَ لَهُمْ اَخُوْهُمْ لُوْطٌ اَلَا تَتَّقُوْنَ ۚ  ', 'Ketika saudara mereka, Lut, berkata kepada mereka, “Mengapa kamu tidak bertakwa?”', '', 'https://everyayah.com/data/Alafasy_128kbps/026161.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:162', 26, 162, 19, 374, 3094, 'اِنِّيْ لَكُمْ رَسُوْلٌ اَمِيْنٌ ۙ ', 'Sesungguhnya aku adalah seorang rasul tepercaya (yang diutus) kepadamu.', '', 'https://everyayah.com/data/Alafasy_128kbps/026162.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:163', 26, 163, 19, 374, 3095, 'فَاتَّقُوا اللّٰهَ وَاَطِيْعُوْنِ ۚ ', 'Maka, bertakwalah kepada Allah dan taatlah kepadaku.', '', 'https://everyayah.com/data/Alafasy_128kbps/026163.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:164', 26, 164, 19, 374, 3096, 'وَمَآ اَسْـَٔلُكُمْ عَلَيْهِ مِنْ اَجْرٍ اِنْ اَجْرِيَ اِلَّا عَلٰى رَبِّ الْعٰلَمِيْنَ ۗ ', 'Aku tidak meminta imbalan kepadamu atas (ajakan) itu. Imbalanku tidak lain hanyalah dari Tuhan semesta alam.', '', 'https://everyayah.com/data/Alafasy_128kbps/026164.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:165', 26, 165, 19, 374, 3097, 'اَتَأْتُوْنَ الذُّكْرَانَ مِنَ الْعٰلَمِيْنَ ۙ ', 'Mengapa kamu mendatangi jenis laki-laki di antara manusia (berbuat homoseks)?', '', 'https://everyayah.com/data/Alafasy_128kbps/026165.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:166', 26, 166, 19, 374, 3098, 'وَتَذَرُوْنَ مَا خَلَقَ لَكُمْ رَبُّكُمْ مِّنْ اَزْوَاجِكُمْۗ بَلْ اَنْتُمْ قَوْمٌ عَادُوْنَ', 'Sementara itu, kamu tinggalkan (perempuan) yang diciptakan Tuhan untuk menjadi istri-istrimu? Kamu (memang) kaum yang melampaui batas.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026166.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:167', 26, 167, 19, 374, 3099, 'قَالُوْا لَىِٕنْ لَّمْ تَنْتَهِ يٰلُوْطُ لَتَكُوْنَنَّ مِنَ الْمُخْرَجِيْنَ  ', 'Mereka menjawab, “Wahai Lut, jika tidak berhenti (melarang kami), niscaya engkau benar-benar akan termasuk orang-orang yang diusir.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026167.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:168', 26, 168, 19, 374, 3100, 'قَالَ اِنِّيْ لِعَمَلِكُمْ مِّنَ الْقَالِيْنَ  ۗ', 'Dia (Lut) berkata, “Sesungguhnya aku termasuk orang-orang yang sangat benci terhadap perbuatanmu.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026168.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:169', 26, 169, 19, 374, 3101, 'رَبِّ نَجِّنِيْ وَاَهْلِيْ مِمَّا يَعْمَلُوْنَ  ', '(Lut berdoa,) “Wahai Tuhanku, selamatkanlah aku dan keluargaku dari apa yang mereka perbuat.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026169.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:170', 26, 170, 19, 374, 3102, 'فَنَجَّيْنٰهُ وَاَهْلَهٗٓ اَجْمَعِيْنَ ۙ ', 'Maka, Kami selamatkan dia bersama semua keluarganya,', '', 'https://everyayah.com/data/Alafasy_128kbps/026170.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:171', 26, 171, 19, 374, 3103, 'اِلَّا عَجُوْزًا فِى الْغٰبِرِيْنَ ۚ  ', 'kecuali seorang perempuan tua (istrinya) yang termasuk golongan (orang-orang kafir) yang tertinggal.', '', 'https://everyayah.com/data/Alafasy_128kbps/026171.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:172', 26, 172, 19, 374, 3104, 'ثُمَّ دَمَّرْنَا الْاٰخَرِيْنَ ۚ ', 'Kemudian, Kami binasakan yang lain.', '', 'https://everyayah.com/data/Alafasy_128kbps/026172.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:173', 26, 173, 19, 374, 3105, 'وَاَمْطَرْنَا عَلَيْهِمْ مَّطَرًاۚ فَسَاۤءَ مَطَرُ الْمُنْذَرِيْنَ ', 'Kami hujani mereka (dengan batu). Betapa buruk hujan yang menimpa orang-orang yang telah diberi peringatan itu.', '', 'https://everyayah.com/data/Alafasy_128kbps/026173.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:174', 26, 174, 19, 374, 3106, 'اِنَّ فِيْ ذٰلِكَ لَاٰيَةً ۗوَمَا كَانَ اَكْثَرُهُمْ مُّؤْمِنِيْنَ  ', 'Sesungguhnya pada yang demikian itu benar-benar terdapat tanda (kekuasaan Allah), tetapi kebanyakan mereka tidak beriman.', '', 'https://everyayah.com/data/Alafasy_128kbps/026174.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:175', 26, 175, 19, 374, 3107, 'وَاِنَّ رَبَّكَ لَهُوَ الْعَزِيْزُ الرَّحِيْمُ ࣖ', 'Sesungguhnya Tuhanmu, Dialah yang benar-benar Maha Perkasa lagi Maha Penyayang.', '', 'https://everyayah.com/data/Alafasy_128kbps/026175.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:176', 26, 176, 19, 374, 3108, 'كَذَّبَ اَصْحٰبُ لْـَٔيْكَةِ الْمُرْسَلِيْنَ ۖ ', 'Penduduk Aikah (Madyan) telah mendustakan para rasul.', '', 'https://everyayah.com/data/Alafasy_128kbps/026176.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:177', 26, 177, 19, 374, 3109, 'اِذْ قَالَ لَهُمْ شُعَيْبٌ اَلَا تَتَّقُوْنَ ۚ ', 'Ketika Syu‘aib berkata kepada mereka, “Mengapa kamu tidak bertakwa?', '', 'https://everyayah.com/data/Alafasy_128kbps/026177.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:178', 26, 178, 19, 374, 3110, 'اِنِّيْ لَكُمْ رَسُوْلٌ اَمِيْنٌ ۙ ', 'Sesungguhnya aku adalah seorang rasul tepercaya (yang diutus) kepadamu.', '', 'https://everyayah.com/data/Alafasy_128kbps/026178.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:179', 26, 179, 19, 374, 3111, 'فَاتَّقُوا اللّٰهَ وَاَطِيْعُوْنِ ۚ ', 'Maka, bertakwalah kepada Allah dan taatlah kepadaku.', '', 'https://everyayah.com/data/Alafasy_128kbps/026179.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:180', 26, 180, 19, 374, 3112, 'وَمَآ اَسْـَٔلُكُمْ عَلَيْهِ مِنْ اَجْرٍ اِنْ اَجْرِيَ اِلَّا عَلٰى رَبِّ الْعٰلَمِيْنَ ۗ ', 'Aku tidak meminta imbalan kepadamu atas (ajakan) itu. Imbalanku tidak lain, kecuali dari Tuhan semesta alam.', '', 'https://everyayah.com/data/Alafasy_128kbps/026180.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:181', 26, 181, 19, 374, 3113, '۞ اَوْفُوا الْكَيْلَ وَلَا تَكُوْنُوْا مِنَ الْمُخْسِرِيْنَ ۚ ', 'Sempurnakanlah takaran dan janganlah kamu termasuk orang-orang yang merugikan orang lain.', '', 'https://everyayah.com/data/Alafasy_128kbps/026181.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:182', 26, 182, 19, 374, 3114, 'وَزِنُوْا بِالْقِسْطَاسِ الْمُسْتَقِيْمِ ۚ ', 'Timbanglah dengan timbangan yang benar.', '', 'https://everyayah.com/data/Alafasy_128kbps/026182.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:183', 26, 183, 19, 374, 3115, 'وَلَا تَبْخَسُوا النَّاسَ اَشْيَاۤءَهُمْ وَلَا تَعْثَوْا فِى الْاَرْضِ مُفْسِدِيْنَ ۚ ', 'Janganlah kamu merugikan manusia dengan mengurangi hak-haknya dan janganlah membuat kerusakan di bumi.', '', 'https://everyayah.com/data/Alafasy_128kbps/026183.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:184', 26, 184, 19, 375, 3116, 'وَاتَّقُوا الَّذِيْ خَلَقَكُمْ وَالْجِبِلَّةَ الْاَوَّلِيْنَ ۗ ', 'Bertakwalah kepada Allah yang telah menciptakanmu dan umat-umat yang terdahulu.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026184.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:185', 26, 185, 19, 375, 3117, 'قَالُوْٓا اِنَّمَآ اَنْتَ مِنَ الْمُسَحَّرِيْنَ ۙ ', 'Mereka berkata, “Sesungguhnya engkau hanyalah termasuk orang-orang yang terkena sihir.', '', 'https://everyayah.com/data/Alafasy_128kbps/026185.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:186', 26, 186, 19, 375, 3118, 'وَمَآ اَنْتَ اِلَّا بَشَرٌ مِّثْلُنَا وَاِنْ نَّظُنُّكَ لَمِنَ الْكٰذِبِيْنَ ۚ ', 'Engkau tidak lain hanyalah seorang manusia seperti kami dan sesungguhnya kami yakin bahwa engkau benar-benar termasuk para pembohong.', '', 'https://everyayah.com/data/Alafasy_128kbps/026186.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:187', 26, 187, 19, 375, 3119, 'فَاَسْقِطْ عَلَيْنَا كِسَفًا مِّنَ السَّمَاۤءِ اِنْ كُنْتَ مِنَ الصّٰدِقِيْنَ ۗ ', 'Maka, jatuhkanlah kepada kami kepingan-kepingan dari langit (agar kami binasa) jika engkau termasuk orang-orang yang benar.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026187.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:188', 26, 188, 19, 375, 3120, 'قَالَ رَبِّيْٓ اَعْلَمُ بِمَا تَعْمَلُوْنَ  ', 'Dia (Syu‘aib) berkata, “Tuhanku paling mengetahui apa yang kamu kerjakan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026188.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:189', 26, 189, 19, 375, 3121, 'فَكَذَّبُوْهُ فَاَخَذَهُمْ عَذَابُ يَوْمِ الظُّلَّةِ ۗاِنَّهٗ كَانَ عَذَابَ يَوْمٍ عَظِيْمٍ ', 'Lalu, mereka mendustakannya (Syu‘aib). Maka, mereka ditimpa azab pada hari yang berawan gelap. Sesungguhnya itu adalah azab hari yang dahsyat.', '', 'https://everyayah.com/data/Alafasy_128kbps/026189.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:190', 26, 190, 19, 375, 3122, 'اِنَّ فِيْ ذٰلِكَ لَاٰيَةً ۗوَمَا كَانَ اَكْثَرُهُمْ مُّؤْمِنِيْنَ  ', 'Sesungguhnya pada yang demikian itu benar-benar terdapat tanda (kekuasaan Allah), tetapi kebanyakan mereka tidak beriman.', '', 'https://everyayah.com/data/Alafasy_128kbps/026190.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:191', 26, 191, 19, 375, 3123, 'وَاِنَّ رَبَّكَ لَهُوَ الْعَزِيْزُ الرَّحِيْمُ ࣖ ', 'Sesungguhnya Tuhanmu, Dialah yang benar-benar Maha Perkasa lagi Maha Penyayang.', '', 'https://everyayah.com/data/Alafasy_128kbps/026191.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:192', 26, 192, 19, 375, 3124, 'وَاِنَّهٗ لَتَنْزِيْلُ رَبِّ الْعٰلَمِيْنَ ۗ  ', 'Sesungguhnya ia (Al-Qur’an) benar-benar diturunkan Tuhan semesta alam.', '', 'https://everyayah.com/data/Alafasy_128kbps/026192.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:193', 26, 193, 19, 375, 3125, 'نَزَلَ بِهِ الرُّوْحُ الْاَمِيْنُ ۙ ', 'Ia (Al-Qur’an) dibawa turun oleh Ruhulamin (Jibril).', '', 'https://everyayah.com/data/Alafasy_128kbps/026193.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:194', 26, 194, 19, 375, 3126, 'عَلٰى قَلْبِكَ لِتَكُوْنَ مِنَ الْمُنْذِرِيْنَ ۙ  ', '(Diturunkan) ke dalam hatimu (Nabi Muhammad) agar engkau menjadi salah seorang pemberi peringatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/026194.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:195', 26, 195, 19, 375, 3127, 'بِلِسَانٍ عَرَبِيٍّ مُّبِيْنٍ ۗ ', '(Diturunkan) dengan bahasa Arab yang jelas.', '', 'https://everyayah.com/data/Alafasy_128kbps/026195.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:196', 26, 196, 19, 375, 3128, 'وَاِنَّهٗ لَفِيْ زُبُرِ الْاَوَّلِيْنَ  ', 'Sesungguhnya ia (Al-Qur’an) benar-benar (disebut) dalam kitab-kitab orang terdahulu.', '', 'https://everyayah.com/data/Alafasy_128kbps/026196.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:197', 26, 197, 19, 375, 3129, 'اَوَلَمْ يَكُنْ لَّهُمْ اٰيَةً اَنْ يَّعْلَمَهٗ عُلَمٰۤؤُا بَنِيْٓ اِسْرَاۤءِيْلَ  ', 'Apakah tidak (cukup) menjadi bukti bagi mereka bahwa ia (Al-Qur’an) diketahui oleh para ulama Bani Israil?', '', 'https://everyayah.com/data/Alafasy_128kbps/026197.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:198', 26, 198, 19, 375, 3130, 'وَلَوْ نَزَّلْنٰهُ عَلٰى بَعْضِ الْاَعْجَمِيْنَ ۙ ', 'Seandainya Kami menurunkannya kepada sebagian dari golongan non-Arab.', '', 'https://everyayah.com/data/Alafasy_128kbps/026198.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:199', 26, 199, 19, 375, 3131, 'فَقَرَاَهٗ عَلَيْهِمْ مَّا كَانُوْا بِهٖ مُؤْمِنِيْنَ ۗ  ', 'Lalu, dia membacakannya kepada mereka (orang-orang kafir), niscaya mereka tidak juga akan beriman kepadanya.', '', 'https://everyayah.com/data/Alafasy_128kbps/026199.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:200', 26, 200, 19, 375, 3132, 'كَذٰلِكَ سَلَكْنٰهُ فِيْ قُلُوْبِ الْمُجْرِمِيْنَ ۗ  ', 'Demikianlah, Kami masukkan (sifat dusta dan ingkar) ke dalam hati para pendurhaka.', '', 'https://everyayah.com/data/Alafasy_128kbps/026200.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:201', 26, 201, 19, 375, 3133, 'لَا يُؤْمِنُوْنَ بِهٖ حَتّٰى يَرَوُا الْعَذَابَ الْاَلِيْمَ  ', 'Mereka tidak akan beriman kepadanya hingga melihat azab yang pedih.', '', 'https://everyayah.com/data/Alafasy_128kbps/026201.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:202', 26, 202, 19, 375, 3134, 'فَيَأْتِيَهُمْ بَغْتَةً وَّهُمْ لَا يَشْعُرُوْنَ ۙ  ', 'Maka, datanglah ia (azab) kepada mereka secara tiba-tiba, sedangkan mereka tidak menyadarinya.', '', 'https://everyayah.com/data/Alafasy_128kbps/026202.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:203', 26, 203, 19, 375, 3135, 'فَيَقُوْلُوْا هَلْ نَحْنُ مُنْظَرُوْنَ ۗ ', 'Lalu, mereka berkata, “Apakah kami diberi penangguhan waktu?”', '', 'https://everyayah.com/data/Alafasy_128kbps/026203.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:204', 26, 204, 19, 375, 3136, 'اَفَبِعَذَابِنَا يَسْتَعْجِلُوْنَ  ', 'Bukankah mereka yang meminta agar azab Kami disegerakan?', '', 'https://everyayah.com/data/Alafasy_128kbps/026204.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:205', 26, 205, 19, 375, 3137, 'اَفَرَءَيْتَ اِنْ مَّتَّعْنٰهُمْ سِنِيْنَ ۙ  ', 'Bagaimana pendapatmu jika kepada mereka Kami berikan kenikmatan hidup beberapa tahun?', '', 'https://everyayah.com/data/Alafasy_128kbps/026205.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:206', 26, 206, 19, 375, 3138, 'ثُمَّ جَاۤءَهُمْ مَّا كَانُوْا يُوْعَدُوْنَ ۙ  ', 'Kemudian, ia (azab) yang diancamkan datang kepada mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/026206.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:207', 26, 207, 19, 376, 3139, 'مَآ اَغْنٰى عَنْهُمْ مَّا كَانُوْا يُمَتَّعُوْنَ ۗ ', 'Niscaya kenikmatan yang mereka rasakan tidak berguna baginya.', '', 'https://everyayah.com/data/Alafasy_128kbps/026207.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:208', 26, 208, 19, 376, 3140, 'وَمَآ اَهْلَكْنَا مِنْ قَرْيَةٍ اِلَّا لَهَا مُنْذِرُوْنَ ۖ  ', 'Kami tidak membinasakan suatu negeri, kecuali setelah ada pemberi peringatan kepadanya.', '', 'https://everyayah.com/data/Alafasy_128kbps/026208.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:209', 26, 209, 19, 376, 3141, 'ذِكْرٰىۚ وَمَا كُنَّا ظٰلِمِيْنَ  ', '(Hal itu) sebagai peringatan. Kami sekali-kali bukanlah orang-orang zalim.', '', 'https://everyayah.com/data/Alafasy_128kbps/026209.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:210', 26, 210, 19, 376, 3142, 'وَمَا تَنَزَّلَتْ بِهِ الشَّيٰطِيْنُ  ', '(Al-Qur’an) itu tidaklah dibawa turun oleh setan-setan.', '', 'https://everyayah.com/data/Alafasy_128kbps/026210.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:211', 26, 211, 19, 376, 3143, 'وَمَا يَنْۢبَغِيْ لَهُمْ وَمَا يَسْتَطِيْعُوْنَ ۗ  ', 'Tidaklah pantas bagi mereka (membawa turun Al-Qur’an itu) dan mereka pun tidak akan sanggup.', '', 'https://everyayah.com/data/Alafasy_128kbps/026211.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:212', 26, 212, 19, 376, 3144, 'اِنَّهُمْ عَنِ السَّمْعِ لَمَعْزُوْلُوْنَ ۗ ', 'Sesungguhnya mereka (setan-setan) benar-benar dijauhkan (dari berita langit).', '', 'https://everyayah.com/data/Alafasy_128kbps/026212.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:213', 26, 213, 19, 376, 3145, 'فَلَا تَدْعُ مَعَ اللّٰهِ اِلٰهًا اٰخَرَ فَتَكُوْنَ مِنَ الْمُعَذَّبِيْنَ', 'Maka, janganlah engkau (Nabi Muhammad) menyembah Tuhan lain bersama Allah. Nanti kamu termasuk orang-orang yang diazab.', '', 'https://everyayah.com/data/Alafasy_128kbps/026213.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:214', 26, 214, 19, 376, 3146, 'وَاَنْذِرْ عَشِيْرَتَكَ الْاَقْرَبِيْنَ ۙ ', 'Berilah peringatan kepada keluargamu yang terdekat.', '', 'https://everyayah.com/data/Alafasy_128kbps/026214.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:215', 26, 215, 19, 376, 3147, 'وَاخْفِضْ جَنَاحَكَ لِمَنِ اتَّبَعَكَ مِنَ الْمُؤْمِنِيْنَ ۚ  ', 'Rendahkanlah hatimu terhadap orang-orang yang mengikutimu, yaitu orang-orang mukmin.', '', 'https://everyayah.com/data/Alafasy_128kbps/026215.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:216', 26, 216, 19, 376, 3148, 'فَاِنْ عَصَوْكَ فَقُلْ اِنِّيْ بَرِيْۤءٌ مِّمَّا تَعْمَلُوْنَ ۚ ', 'Jika mereka mendurhakaimu, katakanlah, “Sesungguhnya aku tidak bertanggung jawab terhadap apa yang kamu kerjakan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/026216.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:217', 26, 217, 19, 376, 3149, 'وَتَوَكَّلْ عَلَى الْعَزِيْزِ الرَّحِيْمِ ۙ ', 'Bertawakallah kepada (Allah) Yang Maha Perkasa lagi Maha Penyayang.', '', 'https://everyayah.com/data/Alafasy_128kbps/026217.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:218', 26, 218, 19, 376, 3150, 'الَّذِيْ يَرٰىكَ حِيْنَ تَقُوْمُ  ', '(Dia) yang melihat ketika engkau berdiri (untuk salat).', '', 'https://everyayah.com/data/Alafasy_128kbps/026218.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:219', 26, 219, 19, 376, 3151, 'وَتَقَلُّبَكَ فِى السّٰجِدِيْنَ  ', 'Dan, (melihat) perubahan gerakan badanmu di antara orang-orang yang sujud.', '', 'https://everyayah.com/data/Alafasy_128kbps/026219.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:220', 26, 220, 19, 376, 3152, 'اِنَّهٗ هُوَ السَّمِيْعُ الْعَلِيْمُ  ', 'Sesungguhnya Dialah Yang Maha Mendengar lagi Maha Mengetahui.', '', 'https://everyayah.com/data/Alafasy_128kbps/026220.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:221', 26, 221, 19, 376, 3153, 'هَلْ اُنَبِّئُكُمْ عَلٰى مَنْ تَنَزَّلُ الشَّيٰطِيْنُ ۗ  ', 'Maukah Aku beritakan kepadamu, kepada siapa setan-setan itu turun?', '', 'https://everyayah.com/data/Alafasy_128kbps/026221.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:222', 26, 222, 19, 376, 3154, 'تَنَزَّلُ عَلٰى كُلِّ اَفَّاكٍ اَثِيْمٍ ۙ ', 'Mereka (setan) turun kepada setiap pendusta lagi banyak berdosa.', '', 'https://everyayah.com/data/Alafasy_128kbps/026222.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:223', 26, 223, 19, 376, 3155, 'يُّلْقُوْنَ السَّمْعَ وَاَكْثَرُهُمْ كٰذِبُوْنَ ۗ  ', 'Mereka menyampaikan hasil pendengarannya, sedangkan kebanyakan mereka adalah para pendusta.', '', 'https://everyayah.com/data/Alafasy_128kbps/026223.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:224', 26, 224, 19, 376, 3156, 'وَالشُّعَرَاۤءُ يَتَّبِعُهُمُ الْغَاوٗنَ ۗ ', 'Para penyair itu diikuti oleh orang-orang yang sesat.', '', 'https://everyayah.com/data/Alafasy_128kbps/026224.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:225', 26, 225, 19, 376, 3157, 'اَلَمْ تَرَ اَنَّهُمْ فِيْ كُلِّ وَادٍ يَّهِيْمُوْنَ ۙ ', 'Tidakkah engkau melihat bahwa mereka merambah setiap lembah kepalsuan543)', '543) Maksud ayat ini adalah bahwa sebagian penyair itu suka bermain kata-kata, tidak mempunyai tujuan yang baik, dan tidak mempunyai pendirian.', 'https://everyayah.com/data/Alafasy_128kbps/026225.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:226', 26, 226, 19, 376, 3158, 'وَاَنَّهُمْ يَقُوْلُوْنَ مَا لَا يَفْعَلُوْنَ ۙ  ', 'dan bahwa mereka mengatakan apa yang mereka sendiri tidak mengerjakan(-nya)?', '', 'https://everyayah.com/data/Alafasy_128kbps/026226.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('26:227', 26, 227, 19, 376, 3159, 'اِلَّا الَّذِيْنَ اٰمَنُوْا وَعَمِلُوا الصّٰلِحٰتِ وَذَكَرُوا اللّٰهَ كَثِيْرًا وَّانْتَصَرُوْا مِنْۢ بَعْدِ مَا ظُلِمُوْا ۗوَسَيَعْلَمُ الَّذِيْنَ ظَلَمُوْٓا اَيَّ مُنْقَلَبٍ يَّنْقَلِبُوْنَ ࣖ ', 'Kecuali (para penyair) yang beriman, beramal saleh, banyak mengingat Allah, dan bangkit membela (kebenaran) setelah terzalimi. Orang-orang yang zalim kelak akan mengetahui ke mana mereka akan kembali.', '', 'https://everyayah.com/data/Alafasy_128kbps/026227.mp3');
PRAGMA foreign_keys = ON;
